// frontend/src/components/workers/WorkerDashboard.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import './WorkerDashboard.css';

const WorkerDashboard = () => {
    const { user } = useAuth();
    const [applications, setApplications] = useState([]);
    const [recommendedJobs, setRecommendedJobs] = useState([]);
    const [stats, setStats] = useState({
        totalApplications: 0,
        pendingApplications: 0,
        acceptedApplications: 0,
        completedJobs: 0,
        totalEarnings: 0
    });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        loadDashboardData();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            // Load applications
            const appsResponse = await api.get('/worker/applications');
            if (appsResponse.data.success) {
                setApplications(appsResponse.data.data);

                // Calculate stats
                const pending = appsResponse.data.data.filter(a => a.status === 'pending').length;
                const accepted = appsResponse.data.data.filter(a => a.status === 'accepted').length;
                const completed = appsResponse.data.data.filter(a => a.job_status === 'completed').length;
                const earnings = appsResponse.data.data
                    .filter(a => a.job_status === 'completed')
                    .reduce((sum, a) => sum + (a.agreed_rate || a.proposed_rate), 0);

                setStats({
                    totalApplications: appsResponse.data.data.length,
                    pendingApplications: pending,
                    acceptedApplications: accepted,
                    completedJobs: completed,
                    totalEarnings: earnings
                });
            }

            // Load recommended jobs
            const jobsResponse = await api.get('/jobs?status=posted');
            if (jobsResponse.data.success) {
                // Filter jobs relevant to worker's skills (simplified for demo)
                setRecommendedJobs(jobsResponse.data.data.slice(0, 3));
            }

        } catch (error) {
            console.error('Error loading dashboard:', error);
            setError('Failed to load dashboard data');
        } finally {
            setLoading(false);
        }
    };

    const formatDate = (dateString) => {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    const getStatusClass = (status) => {
        switch (status) {
            case 'pending': return 'status-pending';
            case 'accepted': return 'status-accepted';
            case 'rejected': return 'status-rejected';
            default: return '';
        }
    };

    if (loading) {
        return <div className="loading-spinner">Loading dashboard...</div>;
    }

    return (
        <div className="worker-dashboard">
            <div className="dashboard-container">
                {/* Welcome Section */}
                <div className="welcome-section">
                    <h1>Welcome back, {user?.name}! 👋</h1>
                    <p>Here's what's happening with your jobs</p>
                </div>

                {/* Stats Grid */}
                <div className="dashboard-stats">
                    <div className="stat-card">
                        <div className="stat-icon">📋</div>
                        <div className="stat-info">
                            <h3>Total Applications</h3>
                            <span className="stat-number">{stats.totalApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">⏳</div>
                        <div className="stat-info">
                            <h3>Pending</h3>
                            <span className="stat-number">{stats.pendingApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">✅</div>
                        <div className="stat-info">
                            <h3>Accepted</h3>
                            <span className="stat-number">{stats.acceptedApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">💰</div>
                        <div className="stat-info">
                            <h3>Total Earned</h3>
                            <span className="stat-number">R {stats.totalEarnings}</span>
                        </div>
                    </div>
                </div>

                {error && <div className="error-message">{error}</div>}

                {/* My Applications */}
                <div className="section-header">
                    <h2>My Applications</h2>
                    <Link to="/applications" className="view-all">View All →</Link>
                </div>

                {applications.length === 0 ? (
                    <div className="empty-state">
                        <div className="empty-icon">📝</div>
                        <h3>No applications yet</h3>
                        <p>Start applying for jobs to see them here</p>
                        <Link to="/jobs" className="btn-primary">Browse Jobs</Link>
                    </div>
                ) : (
                    <div className="applications-grid">
                        {applications.slice(0, 3).map(app => (
                            <div key={app.id} className="application-card">
                                <span className={`application-status ${getStatusClass(app.status)}`}>
                                    {app.status}
                                </span>
                                <h3>{app.job_title}</h3>
                                <div className="application-details">
                                    <div className="detail-item">
                                        <span>📍</span>
                                        <span>{app.township}</span>
                                    </div>
                                    <div className="detail-item">
                                        <span>📅</span>
                                        <span>Applied {formatDate(app.created_at)}</span>
                                    </div>
                                </div>
                                <div className="application-rate">
                                    <span className="rate-label">Your quote:</span>
                                    <span className="rate-value">R {app.proposed_rate}</span>
                                </div>
                                <Link to={`/jobs/${app.job_id}`} className="btn-view">
                                    View Job
                                </Link>
                            </div>
                        ))}
                    </div>
                )}

                {/* Recommended Jobs */}
                <div className="section-header">
                    <h2>Recommended for You</h2>
                    <Link to="/jobs" className="view-all">Browse All →</Link>
                </div>

                <div className="jobs-grid">
                    {recommendedJobs.map(job => (
                        <div key={job.id} className="recommended-job">
                            <h3>{job.title}</h3>
                            <div className="job-meta">
                                <span>📍 {job.township}</span>
                                <span>⏱️ {job.estimated_hours || 'Flexible'}h</span>
                            </div>
                            <p className="job-description">
                                {job.description.substring(0, 80)}...
                            </p>
                            <div className="job-budget">
                                Budget: R {job.budget_min} - R {job.budget_max}
                            </div>
                            <Link to={`/jobs/${job.id}`} className="btn-apply">
                                View & Apply
                            </Link>
                        </div>
                    ))}
                </div>

                {/* Quick Actions */}
                <div className="quick-actions">
                    <h2>Quick Actions</h2>
                    <div className="actions-grid">
                        <Link to="/profile" className="action-card">
                            <span className="action-icon">👤</span>
                            <span className="action-title">Update Profile</span>
                            <span className="action-desc">Add skills, update rates</span>
                        </Link>
                        <Link to="/vouchers/my" className="action-card">
                            <span className="action-icon">🎫</span>
                            <span className="action-title">My Vouchers</span>
                            <span className="action-desc">Check balance & history</span>
                        </Link>
                        <Link to="/jobs" className="action-card">
                            <span className="action-icon">🔍</span>
                            <span className="action-title">Find Work</span>
                            <span className="action-desc">Browse available jobs</span>
                        </Link>
                        <Link to="/safety" className="action-card">
                            <span className="action-icon">🛡️</span>
                            <span className="action-title">Safety Tips</span>
                            <span className="action-desc">Stay safe while working</span>
                        </Link>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default WorkerDashboard;
